function o(e){let a=e.dataset.passwordLength,t=a?document.getElementById(a):null;if(!t)return;let d=()=>{let n=e.minLength;n>0&&e.value.length>0&&e.value.length<n?t.textContent=`Must be at least ${n} characters.`:t.textContent=""};e.addEventListener("input",d)}if(typeof document<"u"){let e=()=>document.querySelectorAll("[data-password-length]").forEach(o);document.readyState==="loading"?document.addEventListener("DOMContentLoaded",e):e()}
